  ('elementary-f29af906-moex-00798', 'elementary-f29af906', 'elementary-f29af906-moex-110-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '有些人認為對犯罪者要處以刑罰，是讓民眾知道犯罪的下場，警惕自己不要犯罪。此種思維是屬於下列 何種刑罰理論？', '["應報理論", "一般預防理論", "特別預防理論", "綜合理論"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00799', 'elementary-f29af906', 'elementary-f29af906-moex-110-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '根據我國憲法增修條文及相關法律規定，甲就其職權相關之國家大政方針，得向乙進行國情報告。關於 甲、乙的職權及其運作，下列敘述何者正確？', '["甲係由乙直接任命之", "甲可對乙提出覆議案", "乙可對甲提出彈劾案", "乙可對甲提出倒閣案"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00800', 'elementary-f29af906', 'elementary-f29af906-moex-110-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '2015年8月我國甲與中國乙本於平等互惠原則，共同簽署海峽兩岸避免雙重課稅及加強稅務合作協議。 上述代表雙方簽署協議的機構甲與乙分別為下列何者？', '["甲為財團法人海峽交流基金會、乙為海峽兩岸關係協會", "甲為海峽兩岸關係協會、乙為財團法人海峽交流基金會", "甲為大陸委員會、乙為海峽兩岸關係協會", "甲為大陸委員會、乙為國務院臺灣事務辦公室"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00801', 'elementary-f29af906', 'elementary-f29af906-moex-110-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '國人A自中國大陸返臺就醫，引起各界輿論關注。行政院院長赴立法院備詢前受訪表示，是否應限縮健 保使用資格，他在擔任政務委員時，就曾提出限縮在大陸的臺胞與旅居國外僑胞的健保資格。行政院院 長前述表示係屬於政府決策過程的那一階段？', '["政策規劃", "政策合法化", "政策執行", "政策評估"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00802', 'elementary-f29af906', 'elementary-f29af906-moex-110-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '依據我國憲法增修條文之規定，下列政府官員，那些是經由「總統提名，立法院同意」的方式任命？', '["立法院院長", "大法官", "行政院院長", "考試委員  ⑤司法院院長"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00803', 'elementary-f29af906', 'elementary-f29af906-moex-110-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '二次大戰後，由於戰後重建及國內發展的需要，各國有別於過去「有限政府」的概念，擴張行政權，追', '["透過軍隊及海 岸巡防維護領海安全", "全民健保採取強制納保的措施", "每四年進行民意代表選舉落實普選", "立法 規範勞工基本工資及職災補償"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00804', 'elementary-f29af906', 'elementary-f29af906-moex-110-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '關於「君主國」與「共和國」之區分，下列敘述何者正確？', '["「君主國」在政治上採取專制制度", "「共和國」在政治上採取民主制度", "「君主國」之國家元首採世襲制度", "「共和國」之國家元首採多人共任"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00805', 'elementary-f29af906', 'elementary-f29af906-moex-110-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '國內某食品集團因為黑心油事件引發眾怒，有網友發起抵制行動，號召民眾拒買該公司相關產品，許多 店家也紛紛響應，拒用該公司產品作為食材。上述抵制行動較屬於下列何種概念？', '["永續性發展", "企業家才能", "共有財悲歌", "消費者主權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00806', 'elementary-f29af906', 'elementary-f29af906-moex-110-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '若新臺幣兌美元的匯率由三十比一變為三十三比一。在其他條件不變下，此一匯率的變化，在國際貿易 上顯示出下列何種意義？', '["進口物品的價格下降", "鼓勵民眾去美國旅遊", "新臺幣貶值刺激出口", "出口業者的損失提高"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00807', 'elementary-f29af906', 'elementary-f29af906-moex-110-b3f42868', 'sub-elementary-f29af906-01', NULL, 'single_choice', '當人工智慧系統AlphaGo戰勝人類九段圍棋高手的那一刻，全人類開始惶惑。有專家預言本世紀末，70% 的職業會被自動化技術取代，將有50%的白領智慧工作者會失業。下列何者最能解決上述的失業問題？', '["採行緊縮性的貨幣政策", "提供就業資訊", "提供符合市場需求的職業訓練", "推動擴張性財政政策"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "57e6993d4375", "answer_pdf_sha1": "215bbf5687be", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL)
